class Solution:
  def lostBits(self, arr: List[str]) -> List[int]:
    """Return an array where each element represents the number of lost bits at that position."
    """
    maxLen = 0
    for str in arr:
      maxLen = max(maxLen, len(str))
    lost = [0] * (maxLen + 1)
    for str in arr:
      len_ = len(str)
      i = 0
      while i < len_:
        if str[i] == '1':
          lost[len_ - i - 1] += 1
        else:
          lost[len_ - i - 1] += 0
        i += 1
    return lost

