class Solution {
 public:
  vector<int> lostBits(vector<string>& arr) {
    int maxLen = 0;
    for (auto str : arr) {
      maxLen = max(maxLen, (int)str.length());
    }
    vector<int> lost(maxLen + 1, 0);
    for (auto str : arr) {
      int len = str.length();
      int i = 0;
      while (i < len) {
        if (str[i] == '1') {
          lost[len - i - 1] += 1;
        } else {
          lost[len - i - 1] += 0;
        }
        i++;
      }
    }
    return lost;
  }
};
int main() {
  vector<string> arr = {"1101", "1001", "101"};
  Solution solution;
  vector<int> lost = solution.lostBits(arr);
  for (auto bit : lost) {
    cout << bit << ' ';
  }
  return 0;
}
